#endif
    memmove(&s.Ti_begstep[dest], &s.Ti_begstep[src], count * sizeof(integertime));
    memmove(&s.Ti_current[dest], &s.Ti_current[src], count * sizeof(integertime));
    memmove(&s.Pos[dest], &s.Pos[src], count * sizeof(Vec3<MyDouble>));
    memmove(&s.Mass[dest], &s.Mass[src], count * sizeof(MyDouble));
    memmove(&s.Vel[dest], &s.Vel[src], count * sizeof(Vec3<MyDouble>));
    memmove(&s.dp[dest], &s.dp[src], count * sizeof(Vec3<MyDouble>));
